// export default Sidebar;

function Sidebar({
    chats,
    setChats,
    activeChatId,
    setActiveChatId
}) {
    const newChat = () => {
        const id = Date.now();
        setChats([{ id, name: "New Chat", messages: [] }, ...chats]);
        setActiveChatId(id);
    };

    const deleteChat = (id) => {
        setChats(chats.filter(c => c.id !== id));
    };

    const renameChat = (id) => {
        const name = prompt("Rename chat");
        if (!name) return;
        setChats(chats.map(c => c.id === id ? { ...c, name } : c));
    };

    return (
        <div className="sidebar">
            <button className="new-chat" onClick={newChat}>
                ➕ New chat
            </button>

            <div className="chat-list">
                {chats.map(chat => (
                    <div
                        key={chat.id}
                        className={`chat-item ${chat.id === activeChatId ? "active" : ""}`}
                        onClick={() => setActiveChatId(chat.id)}
                    >
                        <span>{chat.name}</span>

                        <div className="chat-actions">
                            <button onClick={() => renameChat(chat.id)}>✏️</button>
                            <button onClick={() => deleteChat(chat.id)}>🗑</button>
                            <button>🔗</button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
}

export default Sidebar;
